(286, 'Intel Core i5-14600K', 'Intel Core i5-14600K.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'intel core i5 14600k', 'intel core i5-14600k bộ xử lý chơi game phổ biến cung cấp tỷ lệ giá trên hiệu suất tuyệt vời. có 14 lõi (6p + 8e), 20 luồng, xung nhịp tăng lên đến 5.3ghz, intel uhd graphics 770, hỗ trợ pcie 5.0, khả năng tương thích ddr5 và khả năng chơi game và đa nhiệm mạnh mẽ cho pc chơi game hiện đại.'),
(287, 'AMD Ryzen 9 9950X', 'AMD Ryzen 9 9950X.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'amd ryzen 9 9950x', 'amd ryzen 9 9950x bộ xử lý máy tính để bàn amd cao cấp được xây dựng để chơi game, kết xuất, khối lượng công việc ai và sáng tạo nội dung chuyên nghiệp cao cấp. có 16 lõi, 32 luồng, kiến trúc zen 5, tần số tăng trên 5.7ghz, khả năng tương thích nền tảng am5, hỗ trợ ddr5, hỗ trợ pcie 5.0 và hiệu suất năng lượng nâng cao cho các hệ thống máy tính để bàn thế hệ tiếp theo.'),
(288, 'AMD Ryzen 7 9800X3D', 'AMD Ryzen 7 9800X3D.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'amd ryzen 7 9800x3d', 'amd ryzen 7 9800x3d bộ xử lý chơi game tiên tiến sử dụng công nghệ amd 3d v-cache cho hiệu suất chơi game ưu việt. có 8 lõi, 16 luồng, tối ưu hóa bộ nhớ đệm l3 lớn, khả năng fps chơi game cao, khả năng tương thích am5, hỗ trợ bộ nhớ ddr5, hỗ trợ pcie 5.0 và hiệu suất nhiệt tuyệt vời cho các bản dựng chơi game đam mê.'),
(289, 'AMD Ryzen 5 9600X', 'AMD Ryzen 5 9600X.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'amd ryzen 5 9600x', 'amd ryzen 5 9600x bộ xử lý chơi game amd chính thống mang lại hiệu suất đa lõi mạnh mẽ và khả năng phản hồi chơi game. có 6 lõi, 12 luồng, kiến trúc zen 5, khả năng tương thích với ổ cắm am5, hỗ trợ ddr5, sẵn sàng pcie 5.0 và mức tiêu thụ điện năng hiệu quả phù hợp cho pc chơi game và năng suất.'),
(290, 'Intel Core i3-14100F', 'Intel Core i3-14100F.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'intel core i3 14100f', 'intel core i3-14100f bộ xử lý chơi game để bàn cấp thấp giá cả phải chăng có 4 lõi, 8 luồng, tốc độ xung nhịp cao, khả năng tương thích với intel lga1700, hỗ trợ ddr4 / ddr5 và giá trị mạnh mẽ cho các hệ thống chơi game giá rẻ. yêu cầu card đồ họa chuyên dụng do thiếu đồ họa tích hợp.'),
(291, 'AMD Ryzen 7 7800X3D', 'AMD Ryzen 7 7800X3D.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'amd ryzen 7 7800x3d', 'amd ryzen 7 7800x3d một trong những cpu chơi game phổ biến nhất thế giới được biết đến với hiệu suất và hiệu suất chơi game vượt trội. có 8 lõi, 16 luồng, công nghệ amd 3d v-cache, hỗ trợ ổ cắm am5, khả năng tương thích ddr5, hỗ trợ pcie 5.0 và hiệu suất fps chơi game hàng đầu trong ngành.'),
(292, 'Intel Core Ultra 7 265K', 'Intel Core Ultra 7 265K.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'intel core ultra 7 265k', 'intel core ultra 7 265k bộ xử lý máy tính để bàn intel hiện đại tập trung vào ai có kiến trúc lõi lai tiên tiến, khả năng tăng tốc ai tích hợp, hỗ trợ ddr5, khả năng tương thích pcie 5.0, hiệu quả được cải thiện, hiệu suất chơi game và năng suất mạnh mẽ cho khối lượng công việc điện toán máy tính để bàn thế hệ tiếp theo.'),
(293, 'AMD Ryzen 5 5600', 'AMD Ryzen 5 5600.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'amd ryzen 5 5600', 'amd ryzen 5 5600 bộ xử lý amd được mua rộng rãi mang lại khả năng chi trả và hiệu suất chơi game tuyệt vời. có 6 lõi, 12 luồng, khả năng tương thích với socket am4, hỗ trợ bộ nhớ ddr4, hỗ trợ pcie 4.0, thiết kế tản nhiệt hiệu quả và hiệu suất chơi game mạnh mẽ cho các bản dựng máy tính để bàn chính thống và ngân sách trên toàn thế giới.'),
(294, 'Logitech G Pro X Gaming Headset', 'Logitech G Pro X Gaming Headset.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'logitech g pro x gaming headset', 'logitech g pro x gaming headset tai nghe chơi game thể thao điện tử chuyên nghiệp được thiết kế cho các game thủ và streamer cạnh tranh. có trình điều khiển pro-g 50mm, âm thanh vòm dts headphone: x 2.0, blue vo có thể tháo rời! công nghệ micrô ce, đệm tai bằng mút hoạt tính, kết cấu bằng nhôm và thép bền, card âm thanh bên ngoài usb và khả năng tương thích với pc, playstation, xbox và nintendo switch.'),
(295, 'HyperX Cloud II', 'HyperX Cloud II.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'hyperx cloud ii', 'hyperx cloud ii một trong những tai nghe chơi game phổ biến nhất thế giới được biết đến với sự thoải mái và hiệu suất âm thanh sống động. có trình điều khiển 53mm, âm thanh vòm ảo 7.1, micrô khử tiếng ồn có thể tháo rời, đệm tai bằng mút hoạt tính, độ bền của khung nhôm và khả năng tương thích đa nền tảng để chơi game và giao tiếp.'),
(296, 'Razer BlackShark V2', 'Razer BlackShark V2.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'razer blackshark v2', 'razer blackshark v2 tai nghe chơi game tập trung vào thể thao điện tử nhẹ có trình điều khiển triforce titanium 50mm, thx spatial audio, micrô hyperclear cardioid có thể tháo rời, đệm tai bằng mút hoạt tính, cách ly tiếng ồn thụ động tiên tiến và hỗ trợ card âm thanh usb cho môi trường chơi game cạnh tranh.'),
(297, 'SteelSeries Arctis Nova 7 Wireless', 'SteelSeries Arctis Nova 7 Wireless.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'steelseries arctis nova 7 wireless', 'steelseries arctis nova 7 wireless tai nghe chơi game không dây cao cấp được thiết kế để chơi game, năng suất và giải trí. có âm thanh không gian 360 °, micrô khử tiếng ồn được hỗ trợ bởi ai, kết nối không dây kép (2.4ghz + bluetooth), thời lượng pin dài, thiết kế thoải mái nhẹ và khả năng tương thích đa nền tảng bao gồm pc, playstation và thiết bị di động.'),
(298, 'Sony WH-1000XM5', 'Sony WH-1000XM5.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'sony wh 1000xm5', 'sony wh-1000xm5 tai nghe văn phòng và du lịch không dây hàng đầu trong ngành có tính năng khử tiếng ồn chủ động tiên tiến, chất lượng âm thanh cao cấp, thời lượng pin 30 giờ, điều khiển cảm ứng, ghép nối nhiều thiết bị, giảm tiếng ồn micrô dựa trên ai, sạc nhanh usb-c và tiện nghi công thái học nhẹ cho công việc văn phòng và giải trí.'),
(299, 'Bose QuietComfort Ultra Headphones', 'Bose QuietComfort Ultra Headphones.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'bose quietcomfort ultra headphones', 'bose quietcomfort ultra headphones tai nghe văn phòng và du lịch cao cấp được thiết kế để mang lại sự thoải mái đặc biệt và khử tiếng ồn chủ động. có âm thanh không gian sống động, công nghệ anc tiên tiến, điều chỉnh âm thanh có độ trung thực cao, kết nối không dây bluetooth, thời lượng pin dài và thiết kế nhẹ sang trọng phù hợp cho mục đích sử dụng chuyên nghiệp và hàng ngày.'),
(300, 'JBL Quantum 100', 'JBL Quantum 100.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'jbl quantum 100', 'jbl quantum 100 tai nghe chơi game giá cả phải chăng có âm thanh jbl quantumsound signature, micrô cần có thể tháo rời, thiết kế over-ear nhẹ, đệm tai bằng mút hoạt tính và khả năng tương thích với pc, playstation, xbox, nintendo switch và các thiết bị chơi game di động.'),
(301, 'Corsair HS80 RGB Wireless', 'Corsair HS80 RGB Wireless.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'corsair hs80 rgb wireless', 'corsair hs80 rgb wireless tai nghe chơi game không dây hiệu suất cao có âm thanh không gian dolby atmos, kết nối không dây có độ trễ thấp, micrô đa hướng cấp phát sóng, ánh sáng rgb, bọt hoạt tính thoải mái, độ bền khung nhôm và thời lượng pin lên đến 20 giờ cho các phiên chơi game và phát trực tuyến.'),
(302, 'Sennheiser HD 450BT', 'Sennheiser HD 450BT.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'sennheiser hd 450bt', 'sennheiser hd 450bt tai nghe văn phòng và giải trí không dây cung cấp khả năng khử tiếng ồn chủ động, âm thanh nổi chất lượng cao, kết nối bluetooth 5.0, sạc usb-c, thiết kế nhẹ có thể gập lại, thời lượng pin dài và hỗ trợ trợ lý giọng nói và quy trình làm việc năng suất di động.'),
(303, 'ASUS ROG Delta S', 'ASUS ROG Delta S.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus rog delta s', 'asus rog delta s tai nghe chơi game cao cấp có công nghệ ess 9281 quad dac, micrô khử tiếng ồn ai, ánh sáng rgb, thiết kế tiện dụng nhẹ, chứng nhận âm thanh độ phân giải cao, kết nối usb-c và hiệu suất âm thanh chơi game đắm chìm cho các thiết lập chơi game cạnh tranh và thông thường.'),
(304, 'TP-Link Archer AX55', 'TP-Link Archer AX55.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'tp link archer ax55', 'tp-link archer ax55 bộ định tuyến băng tần kép wi-fi 6 phổ biến được thiết kế để chơi game, phát trực tuyến và kết nối nhà thông minh. có tốc độ không dây ax3000 lên đến 3000mbps, hoạt động băng tần kép 2.4ghz và 5ghz, công nghệ ofdma và mu-mimo, bảo mật wpa3, cổng gigabit ethernet, kết nối usb 3.0 và vùng phủ sóng mạnh mẽ cho các ngôi nhà từ trung bình đến lớn.'),
(305, 'ASUS RT-AX58U', 'ASUS RT-AX58U.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus rt ax58u', 'asus rt-ax58u bộ định tuyến wi-fi 6 được công nhận rộng rãi được thiết kế để chơi game và kết nối mạng gia đình tốc độ cao. có hiệu suất không dây ax3000, bảo mật mạng aiprotection pro, mu-mimo, ofdma, hỗ trợ băng tần kép, qos thích ứng, khả năng tương thích aimesh và kết nối gigabit lan/wan cho hiệu suất độ trễ thấp ổn định.'),
(306, 'TP-Link Deco X20', 'TP-Link Deco X20.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'tp link deco x20', 'tp-link deco x20 hệ thống wi-fi 6 lưới phổ biến cung cấp vùng phủ sóng không dây liền mạch cho toàn bộ ngôi nhà. có tốc độ băng tần kép ax1800, công nghệ mạng lưới, kiểm soát của phụ huynh, bảo mật wpa3, chuyển vùng thông minh, hỗ trợ nhiều thiết bị được kết nối và quản lý dựa trên ứng dụng cho nhà thông minh hiện đại.'),
(307, 'ASUS TUF Gaming AX4200', 'ASUS TUF Gaming AX4200.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus tuf gaming ax4200', 'asus tuf gaming ax4200 bộ định tuyến wi-fi 6 tập trung vào chơi game được thiết kế để chơi game có độ trễ thấp và kết nối tốc độ cao ổn định. có tốc độ không dây ax4200, ưu tiên cổng chơi game, hỗ trợ aimesh, thiết kế làm mát tiên tiến, qos thích ứng, bảo mật wpa3 và khả năng xử lý đa thiết bị mạnh mẽ.');

